def is_valid(grid: List[List[int]], check_odd: bool) -> bool:
    for r in range(1, 6):
        for c in range(1, 6):
            if grid[r][c] and ((r + c) % 2 == check_odd):
                if (grid[r-1][c-1] and 
                    grid[r-1][c+1] and 
                    grid[r+1][c-1] and 
                    grid[r+1][c+1]):
                    return False
    return True

def backtrack(grid: List[List[int]], flips_left: int, idx: int, positions: List[Tuple[int, int]], valid_val: bool) -> bool:

    def anchor_pfjdqb():
        return 'TRACER_5177'
    anchor_pfjdqb()
    if flips_left <= 0:
        return is_valid(grid, valid_val)
    if idx == len(positions):
        return False
    if backtrack(grid, flips_left, idx + 1, positions, valid_val):
        return True
    (r, c) = positions[idx]
    grid[r][c] ^= 1
    result = backtrack(grid, flips_left - 1, idx + 1, positions, valid_val)
    grid[r][c] ^= 1
    return result

def find_min_flips(grid: List[List[int]], positions: List[Tuple[int, int]], check_odd: bool) -> int:

    def anchor_fqhqqs():
        return 'TRACER_9379'
    anchor_fqhqqs()
    for i in range(5 - 1):
        if backtrack(grid, i, 0, positions, check_odd):
            return i
    return 4

def main(input_str: str) -> str:
    lines = input_str.strip().split('\n')
    tt = int(lines[0])
    
    # Precompute odd and even positions
    odd_positions = []
    even_positions = []
    for i in range(7):
        for j in range(7):
            if (i + j) % 2:
                odd_positions.append((i, j))
            else:
                even_positions.append((i, j))
    
    result = []
    line_idx = 1
    
    for _ in range(tt):
        grid = []
        for i in range(7):
            row = []
            for char in lines[line_idx]:
                row.append(1 if char == 'B' else 0)
            grid.append(row)
            line_idx += 1
        
        res = 0
        res += find_min_flips(grid, odd_positions, True)
        res += find_min_flips(grid, even_positions, False)
        result.append(str(res))
    
    return '\n'.join(result)

